import{_ as e,o as s,c as t,a2 as i}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"能力值详解","description":"","frontmatter":{},"headers":[],"relativePath":"guide/characters-stats.md","filePath":"guide/characters-stats.md","lastUpdated":1781113496000}'),l={name:"guide/characters-stats.md"};function n(o,a,r,p,h,d){return s(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="能力值详解" tabindex="-1">能力值详解 <a class="header-anchor" href="#能力值详解" aria-label="Permalink to &quot;能力值详解&quot;">​</a></h1><h2 id="最大生命值" tabindex="-1">最大生命值 <a class="header-anchor" href="#最大生命值" aria-label="Permalink to &quot;最大生命值&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基础最大生命值 = 初始生命值 + (等级-1) × (17 + 0.68 × 初始生命值) + 基础力量 × 9</span></span>
<span class="line"><span>最大生命值 = 基础最大生命值 + (额外力量 × 9) + 额外生命值加成</span></span></code></pre></div><h2 id="最大魔法值" tabindex="-1">最大魔法值 <a class="header-anchor" href="#最大魔法值" aria-label="Permalink to &quot;最大魔法值&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基础最大魔法值 = 初始魔法值 + (等级-1) × (1.5 + 0.14 × 初始魔法值) + 基础智力 × 8</span></span>
<span class="line"><span>最大魔法值 = 基础最大魔法值 + (额外智力 × 8) + 额外魔法值加成</span></span></code></pre></div><h2 id="爆发能量" tabindex="-1">爆发能量 <a class="header-anchor" href="#爆发能量" aria-label="Permalink to &quot;爆发能量&quot;">​</a></h2><ul><li>最大值 200 点</li><li>释放战技和爆发技消耗</li><li>造成/受到伤害获得少量爆发能量</li></ul><h2 id="行动速度" tabindex="-1">行动速度 <a class="header-anchor" href="#行动速度" aria-label="Permalink to &quot;行动速度&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>行动系数 = 行动速度 / 1500 × 100%（保留两位小数）</span></span></code></pre></div><p>行动系数上限 <strong>90%</strong>（速度 1350 时达到上限），用于减少硬直时间。</p><h2 id="攻击力" tabindex="-1">攻击力 <a class="header-anchor" href="#攻击力" aria-label="Permalink to &quot;攻击力&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基础攻击力 = 初始攻击力 + (等级-1) × (0.95 + 0.045 × 初始攻击力) + 基础核心属性</span></span>
<span class="line"><span>总攻击力 = 基础攻击力 + 额外攻击力加成</span></span></code></pre></div><h2 id="物理护甲" tabindex="-1">物理护甲 <a class="header-anchor" href="#物理护甲" aria-label="Permalink to &quot;物理护甲&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>物理伤害减免 = 护甲 / (护甲 + 240) × 100%</span></span></code></pre></div><h2 id="加速系数" tabindex="-1">加速系数 <a class="header-anchor" href="#加速系数" aria-label="Permalink to &quot;加速系数&quot;">​</a></h2><p>用于削减魔法吟唱时间。当角色吟唱魔法时，吟唱时间替代硬直时间插入顺序表，此时用加速系数（而非行动系数）来削减时间。</p><h2 id="闪避率" tabindex="-1">闪避率 <a class="header-anchor" href="#闪避率" aria-label="Permalink to &quot;闪避率&quot;">​</a></h2><p>仅对普通攻击有效。投掷 100 以内随机数，小于闪避率则闪避成功。</p><h2 id="暴击率-暴击伤害" tabindex="-1">暴击率 &amp; 暴击伤害 <a class="header-anchor" href="#暴击率-暴击伤害" aria-label="Permalink to &quot;暴击率 &amp; 暴击伤害&quot;">​</a></h2><ul><li>初始暴击率：<strong>5%</strong></li><li>初始暴击伤害：<strong>125%</strong></li><li>任何伤害计算减伤后，进行暴击检定</li></ul><h2 id="冷却缩减" tabindex="-1">冷却缩减 <a class="header-anchor" href="#冷却缩减" aria-label="Permalink to &quot;冷却缩减&quot;">​</a></h2><p>减少所有主动技能（战技、魔法、爆发技）的冷却时间。</p><h2 id="生命回复-魔法回复" tabindex="-1">生命回复 &amp; 魔法回复 <a class="header-anchor" href="#生命回复-魔法回复" aria-label="Permalink to &quot;生命回复 &amp; 魔法回复&quot;">​</a></h2><p>时间流逝时按比例回复：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>回复量 = 回复值 × 流逝的单位时间</span></span></code></pre></div><p>例如生命回复 0.5，时间流逝 1 秒 → 回复 0.5。</p><h2 id="生命偷取-吸血" tabindex="-1">生命偷取（吸血） <a class="header-anchor" href="#生命偷取-吸血" aria-label="Permalink to &quot;生命偷取（吸血）&quot;">​</a></h2><p>造成伤害时，按比例吸取生命值转化为治疗。</p><h2 id="护盾值" tabindex="-1">护盾值 <a class="header-anchor" href="#护盾值" aria-label="Permalink to &quot;护盾值&quot;">​</a></h2><ul><li>区分物理护盾和魔法护盾</li><li>护盾生效期间替代生命值结算伤害</li><li>护盾耗尽后溢出伤害由生命值承担</li></ul><h2 id="攻击距离-移动距离" tabindex="-1">攻击距离 &amp; 移动距离 <a class="header-anchor" href="#攻击距离-移动距离" aria-label="Permalink to &quot;攻击距离 &amp; 移动距离&quot;">​</a></h2><p>在战棋地图上使用曼哈顿距离。基础攻击距离由武器提供，基础移动距离由角色定位提供。</p>`,32)])])}const b=e(l,[["render",n]]);export{u as __pageData,b as default};
